using System.ComponentModel.DataAnnotations;

namespace sv_fdcadc6e35fd487cbc64965d67cbba99.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Range(0, 9999, ErrorMessage = "Quantity must be between 0 and 9999.")]
    public int Quantity { get; set; }

    [Range(0.01, double.MaxValue, ErrorMessage = "Unit Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;
}

using sv_fdcadc6e35fd487cbc64965d67cbba99.Models;

namespace sv_fdcadc6e35fd487cbc64965d67cbba99.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.50m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 12.99m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Cable", Quantity = 500, UnitPrice = 9.99m, Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 45, UnitPrice = 89.95m, Category = "Clothing" },
        new Product { Id = 6, Name = "Granola Bars (12-pack)", Quantity = 200, UnitPrice = 6.49m, Category = "Food" }
    };

    public Task<List<Product>> GetAllAsync()
    {
        var copy = _products.Select(p => new Product
        {
            Id = p.Id,
            Name = p.Name,
            Quantity = p.Quantity,
            UnitPrice = p.UnitPrice,
            Category = p.Category
        }).ToList();

        return Task.FromResult(copy);
    }

    public Task UpdateAsync(Product product)
    {
        var existing = _products.FirstOrDefault(p => p.Id == product.Id);
        if (existing is not null)
        {
            existing.Name = product.Name;
            existing.Quantity = product.Quantity;
            existing.UnitPrice = product.UnitPrice;
            existing.Category = product.Category;
        }

        return Task.CompletedTask;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_fdcadc6e35fd487cbc64965d67cbba99.Models
@using sv_fdcadc6e35fd487cbc64965d67cbba99.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProductId == product.Id)
                {
                    <tr>
                        <td>
                            <input class="form-control" @bind="_editModel!.Name" />
                            @if (GetValidationError(nameof(Product.Name)) is string nameErr)
                            {
                                <div class="text-danger small">@nameErr</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_editModel!.Quantity" />
                            @if (GetValidationError(nameof(Product.Quantity)) is string qtyErr)
                            {
                                <div class="text-danger small">@qtyErr</div>
                            }
                        </td>
                        <td>
                            <input type="number" step="0.01" class="form-control" @bind="_editModel!.UnitPrice" />
                            @if (GetValidationError(nameof(Product.UnitPrice)) is string priceErr)
                            {
                                <div class="text-danger small">@priceErr</div>
                            }
                        </td>
                        <td>
                            <select class="form-select" @bind="_editModel!.Category">
                                <option value="">-- Select --</option>
                                @foreach (var cat in _categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (GetValidationError(nameof(Product.Category)) is string catErr)
                            {
                                <div class="text-danger small">@catErr</div>
                            }
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm me-1" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => Edit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private int? _editingProductId;
    private Product? _editModel;
    private Dictionary<string, string> _validationErrors = new();

    private static readonly string[] _categories = { "Electronics", "Clothing", "Food", "Other" };

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void Edit(Product product)
    {
        _editingProductId = product.Id;
        _editModel = new Product
        {
            Id = product.Id,
            Name = product.Name,
            Quantity = product.Quantity,
            UnitPrice = product.UnitPrice,
            Category = product.Category
        };
        _validationErrors.Clear();
    }

    private async Task SaveAsync()
    {
        if (_editModel is null) return;

        _validationErrors.Clear();

        var context = new System.ComponentModel.DataAnnotations.ValidationContext(_editModel);
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
        if (!System.ComponentModel.DataAnnotations.Validator.TryValidateObject(_editModel, context, results, true))
        {
            foreach (var result in results)
            {
                foreach (var member in result.MemberNames)
                {
                    _validationErrors[member] = result.ErrorMessage ?? "Invalid";
                }
            }
            return;
        }

        await InventoryService.UpdateAsync(_editModel);

        var target = _products!.First(p => p.Id == _editModel.Id);
        target.Name = _editModel.Name;
        target.Quantity = _editModel.Quantity;
        target.UnitPrice = _editModel.UnitPrice;
        target.Category = _editModel.Category;

        _editingProductId = null;
        _editModel = null;
    }

    private void Cancel()
    {
        _editingProductId = null;
        _editModel = null;
        _validationErrors.Clear();
    }

    private string? GetValidationError(string fieldName)
    {
        return _validationErrors.TryGetValue(fieldName, out var error) ? error : null;
    }
}

